import{_ as a,o as r,c as t,ag as o}from"./chunks/framework.Cycwnjj0.js";const h=JSON.parse('{"title":"Function: prepareDeckDataset()","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://sqlrooms.org/api/deck/functions/prepareDeckDataset.html"}]]},"headers":[],"relativePath":"api/deck/functions/prepareDeckDataset.md","filePath":"api/deck/functions/prepareDeckDataset.md"}'),s={name:"api/deck/functions/prepareDeckDataset.md"};function n(c,e,i,d,l,p){return r(),t("div",null,[...e[0]||(e[0]=[o('<p><a href="./../">@sqlrooms/deck</a> / prepareDeckDataset</p><h1 id="function-preparedeckdataset" tabindex="-1">Function: prepareDeckDataset() <a class="header-anchor" href="#function-preparedeckdataset" aria-label="Permalink to &quot;Function: prepareDeckDataset()&quot;">​</a></h1><blockquote><p><strong>prepareDeckDataset</strong>(<code>options</code>): <a href="./../type-aliases/PreparedDeckDataset.html"><code>PreparedDeckDataset</code></a></p></blockquote><p>Build the reusable deck-facing geometry helpers for one resolved Arrow table.</p><p>This is the expensive preparation step that <code>preparedDatasetStore</code> caches. It accepts one resolved Arrow table plus a geometry column/hint and turns the source geometry into canonical deck-facing outputs that can be reused by multiple layers and multiple <code>DeckJsonMap</code> instances.</p><p>Supported input geometry forms:</p><ul><li>native GeoArrow columns Already columnar and geometry-aware. These are the cheapest inputs: preparation mainly does geometry-column detection plus lightweight wrapper shaping so GeoArrow-capable deck layers can consume the Arrow table/vector directly.</li><li>WKB / GeoArrow WKB columns Binary geometry needs decoding because deck layers cannot render raw WKB bytes. Preparation promotes the binary values into deck-ready geometry structures for GeoArrow layers and GeoJSON-binary fallback layers.</li><li>WKT / GeoArrow WKT columns Text geometry likewise needs parsing before deck can render it. This has a similar cost profile to WKB, but starts from text parsing rather than binary decoding.</li></ul><p>These transformations are necessary because the input table shape is chosen by the query/data source, while deck expects render-oriented geometry payloads. The canonical outputs produced here are:</p><ul><li>GeoArrow layer data A <code>PreparedGeoArrowLayerData</code> payload for GeoArrow-native deck layers, either forwarded directly from native GeoArrow inputs or promoted from WKB/WKT into a GeoArrow-like representation.</li><li>GeoJSON-binary data A binary GeoJSON-style payload for layers such as <code>GeoJsonLayer</code> that do not consume GeoArrow inputs directly.</li></ul><p>The returned object also memoizes:</p><ul><li>geometry column detection</li><li>GeoArrow layer payloads</li><li>GeoJSON-binary fallbacks</li></ul><p>Caching at this level lets deck reuse geometry decoding and shaping work even when the upstream query result is already cached by another system such as Mosaic&#39;s query manager.</p><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th></tr></thead><tbody><tr><td><code>options</code></td><td><code>PrepareDeckDatasetOptions</code></td></tr></tbody></table><h2 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h2><p><a href="./../type-aliases/PreparedDeckDataset.html"><code>PreparedDeckDataset</code></a></p>',16)])])}const m=a(s,[["render",n]]);export{h as __pageData,m as default};
